import re

def evaluate(expr: str) -> float:
    """
    Evaluates a string arithmetic expression containing +, -, *, /, (), 
    unary +/-, and non-negative integer or decimal literals.

    Args:
        expr: The arithmetic expression string to evaluate.

    Returns:
        The evaluated result as a float.

    Raises:
        ValueError: If the expression is malformed or contains invalid characters.
        ZeroDivisionError: If a division by zero is attempted.
    """
    def tokenize(s: str) -> list:
        tokens = []
        i = 0
        while i < len(s):
            if s[i].isspace():
                i += 1
                continue
            if s[i].isdigit() or s[i] == '.':
                start = i
                dot_count = 0
                while i < len(s) and (s[i].isdigit() or s[i] == '.'):
                    if s[i] == '.':
                        dot_count += 1
                    i += 1
                if dot_count > 1:
                    raise ValueError(f"Invalid numeric literal: {s[start:i]}")
                num_str = s[start:i]
                try:
                    tokens.append(float(num_str))
                except ValueError:
                    raise ValueError(f"Invalid numeric literal: {num_str}")
                continue
            if s[i] in "+-*/()":
                tokens.append(s[i])
                i += 1
                continue
            raise ValueError(f"Invalid character in expression: {s[i]}")
        return tokens

    class Parser:
        def __init__(self, tokens: list):
            self.tokens = tokens
            self.pos = 0

        def _peek(self) -> any:
            return self.tokens[self.pos] if self.pos < len(self.tokens) else None

        def _consume(self, expected: any = None) -> any:
            token = self._peek()
            if token is None:
                raise ValueError("Unexpected end of expression")
            if expected is not None and token != expected:
                raise ValueError(f"Expected {expected}, found {token}")
            self.pos += 1
            return token

        def parse_expression(self) -> float:
            # Handles + and - (lowest precedence, left-associative)
            result = self.parse_term()
            while self._peek() in ('+', '-'):
                op = self._consume()
                right = self.parse_term()
                if op == '+':
                    result += right
                else:
                    result -= right
            return result

        def parse_term(self) -> float:
            # Handles * and / (medium precedence, left-associative)
            result = self.parse_factor()
            while self._peek() in ('*', '/'):
                op = self._consume()
                right = self.parse_factor()
                if op == '*':
                    result *= right
                else:
                    if right == 0.0:
                        raise ZeroDivisionError("Division by zero")
                    result /= right
            return result

        def parse_factor(self) -> float:
            # Handles unary + and - (high precedence)
            if self._peek() == '+':
                self._consume('+')
                return self.parse_factor()
            if self._peek() == '-':
                self._consume('-')
                return -self.parse_factor()
            return self.parse_primary()

        def parse_primary(self) -> float:
            # Handles numbers and parentheses (highest precedence)
            token = self._peek()
            if token == '(':
                self._consume('(')
                result = self.parse_expression()
                self._consume(')')
                return result
            if isinstance(token, float):
                return self._consume()
            raise ValueError(f"Unexpected token: {token}")

        def parse(self) -> float:
            if not self.tokens:
                raise ValueError("Empty expression")
            result = self.parse_expression()
            if self.pos < len(self.tokens):
                raise ValueError(f"Trailing tokens: {self.tokens[self.pos:]}")
            return result

    if not isinstance(expr, str):
        raise ValueError("Expression must be a string")

    tokens = tokenize(expr)
    parser = Parser(tokens)
    return float(parser.parse())
