import re
from typing import List, Union

def evaluate(expr: str) -> float:
    """
    Evaluates a mathematical string expression containing +, -, *, /, parentheses,
    and unary +/- operators. Returns the result as a float.

    Args:
        expr: The arithmetic expression string to evaluate.

    Returns:
        The evaluated result as a float.

    Raises:
        ValueError: If the expression is malformed or contains invalid characters.
    """
    # Tokenize the expression using regex
    # Groups: numbers (including decimals), operators/parens
    token_pattern = re.compile(r"\s*(\d+\.?\d*|\.\d+|[+\-*/()])\s*")
    tokens: List[str] = []

    # Verify there are no illegal characters by checking if the reconstructed 
    # string (without whitespace) matches the tokens found.
    clean_expr = "".join(expr.split())
    if not clean_expr:
        raise ValueError("Empty expression")

    for match in token_pattern.finditer(expr):
        tokens.append(match.group(1))

    # Validate that we didn't skip any non-whitespace characters
    if "".join(tokens) != clean_expr:
        raise ValueError("Invalid characters in expression")

    def get_precedence(op: str) -> int:
        if op in ("+", "-"):
            return 1
        if op in ("*", "/"):
            return 2
        return 0

    def apply_op(ops: List[str], values: List[float]) -> None:
        if len(values) < 2:
            raise ValueError("Invalid expression: insufficient operands")
        right = values.pop()
        left = values.pop()
        op = ops.pop()
        if op == "+":
            values.append(left + right)
        elif op == "-":
            values.append(left - right)
        elif op == "*":
            values.append(left * right)
        elif op == "/":
            if right == 0:
                raise ValueError("Division by zero")
            values.append(left / right)

    values: List[float] = []
    ops: List[str] = []
    i = 0
    while i < len(tokens):
        token = tokens[i]

        if token == "(":
            ops.append(token)
        elif token == ")":
            while ops and ops[-1] != "(":
                apply_op(ops, values)
            if not ops:
                raise ValueError("Mismatched parentheses")
            ops.pop()  # Pop "("
        elif token in ("+", "-") and (i == 0 or tokens[i-1] in ("(", "+", "-", "*", "/")):
            # Handle unary operators by pushing 0 as a dummy operand for + or -
            # e.g., "-5" becomes "0 - 5"
            values.append(0.0)
            ops.append(token)
        elif token in ("+", "-", "*", "/"):
            while ops and get_precedence(ops[-1]) >= get_precedence(token):
                apply_op(ops, values)
            ops.append(token)
        else:
            try:
                values.append(float(token))
            except ValueError:
                raise ValueError(f"Invalid token: {token}")
        i += 1

    while ops:
        if ops[-1] == "(":
            raise ValueError("Mismatched parentheses")
        apply_op(ops, values)

    if len(values) != 1:
        raise ValueError("Malformed expression")

    return float(values[0])
